import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjLegend } from "./OjLegend";
export { OjLegend };

/**
 * Create an instance of [[OjLegend]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojLegend(driver, By.id('my-oj-legend'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojLegend(driver: DriverLike, by: By): Promise<OjLegend> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjLegend
  if (!(webEl instanceof OjLegend)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-legend>`);
  }
  return webEl;
}

register("oj-legend", OjLegend);
